#!/usr/bin/env dotnet
// friday13.cs — Find earliest Friday the 13th and count them in a 400-year cycle

// Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
DateTime? earliest = null;

while (earliest is null)
{
    if (date.DayOfWeek == DayOfWeek.Friday)
        earliest = date;
    else
        date = date.AddMonths(1);
}

Console.WriteLine($"Earliest Friday the 13th (proleptic Gregorian): {earliest:yyyy-MM-dd}");
Console.WriteLine();

// Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
var start = new DateTime(1, 1, 13);
var end = new DateTime(401, 1, 1);

for (var d = start; d < end; d = d.AddMonths(1))
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        count++;
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");
Console.WriteLine();

// Bonus: distribution by day of week for the 13th
Console.WriteLine("Distribution of day-of-week for the 13th (400-year cycle):");
var dow = new int[7];
for (var d = start; d < end; d = d.AddMonths(1))
    dow[(int)d.DayOfWeek]++;

foreach (DayOfWeek day in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {day,-9}: {dow[(int)day]}");

